     1в†’#!/usr/bin/env node
     2в†’/**
     3в†’ * Incremental Email Fetch CLI (T042a)
     4в†’ *
     5в†’ * Wires together Gmail API integration (T037), email fetching (T038b),
     6в†’ * and Prisma persistence (T042) to fetch and persist new emails since
     7в†’ * the last recorded timestamp in the database.
     8в†’ *
     9в†’ * Usage:
    10в†’ *   npm run fetch:emails                    # Fetch since last DB timestamp
    11в†’ *   npm run fetch:emails -- --since=2024-01-01  # Fetch since custom date
    12в†’ */
    13в†’
    14в†’import * as fs from 'fs';
    15в†’import * as path from 'path';
    16в†’import { GmailClient, OAuth2Tokens } from '../gmail/gmail-client';
    17в†’import { EmailFetcher, EmailMessage } from '../gmail/email-fetcher';
    18в†’import { EmailRepository } from '../persistence/email-repository';
    19в†’import { loadEnvironment } from '../config/env';
    20в†’
    21в†’/**
    22в†’ * Options for fetchAndPersistEmails function
    23в†’ */
    24в†’export interface FetchAndPersistOptions {
    25в†’  gmailClient: GmailClient;
    26в†’  emailFetcher: EmailFetcher;
    27в†’  repository: EmailRepository;
    28в†’  sinceDate?: Date; // Optional: Override last DB timestamp
    29в†’}
    30в†’
    31в†’/**
    32в†’ * Error details for fetch/persist operations
    33в†’ */
    34в†’export interface FetchError {
    35в†’  type: 'authentication' | 'fetch' | 'persistence';
    36в†’  message: string;
    37в†’  originalError?: unknown;
    38в†’}
    39в†’
    40в†’/**
    41в†’ * Result summary for fetch and persist operation
    42в†’ */
    43в†’export interface FetchAndPersistResult {
    44в†’  success: boolean;
    45в†’  fetchedCount: number;
    46в†’  persistedCount: number;
    47в†’  sinceTimestamp: Date | null;
    48в†’  errors: FetchError[];
    49в†’  startTime: Date;
    50в†’  endTime: Date;
    51в†’  durationMs: number;
    52в†’}
    53в†’
    54в†’/**
    55в†’ * Fetch and persist new emails since last database timestamp
    56в†’ *
    57в†’ * This function implements the core logic for incremental email fetching:
    58в†’ * 1. Query last email timestamp from database (unless sinceDate provided)
    59в†’ * 2. Fetch new emails from Gmail API since that timestamp
    60в†’ * 3. Persist emails using Prisma batch upsert
    61в†’ * 4. Return detailed result summary with error handling
    62в†’ *
    63в†’ * @param options - Configuration for Gmail client, fetcher, and repository
    64в†’ * @returns Result summary with counts, timestamps, and any errors
    65в†’ *
    66в†’ * @example
    67в†’ * ```typescript
    68в†’ * const result = await fetchAndPersistEmails({
    69в†’ *   gmailClient: new GmailClient(auth),
    70в†’ *   emailFetcher: new EmailFetcher(gmailClient),
    71в†’ *   repository: new EmailRepository(),
    72в†’ * });
    73в†’ *
    74в†’ * console.log(`Fetched ${result.fetchedCount} emails, persisted ${result.persistedCount}`);
    75в†’ * ```
    76в†’ */
    77в†’export async function fetchAndPersistEmails(options: FetchAndPersistOptions): Promise<FetchAndPersistResult> {
    78в†’  const { gmailClient, emailFetcher, repository, sinceDate } = options;
    79в†’
    80в†’  const startTime = new Date();
    81в†’  const result: FetchAndPersistResult = {
    82в†’    success: false,
    83в†’    fetchedCount: 0,
    84в†’    persistedCount: 0,
    85в†’    sinceTimestamp: null,
    86в†’    errors: [],
    87в†’    startTime,
    88в†’    endTime: startTime, // Will be updated at end
    89в†’    durationMs: 0,
    90в†’  };
    91в†’
    92в†’  try {
    93в†’    // Step 1: Check Gmail authentication
    94в†’    const authStatus = await gmailClient.getAuthStatus();
    95в†’    if (!authStatus.authenticated || !authStatus.tokenValid) {
    96в†’      result.errors.push({
    97в†’        type: 'authentication',
    98в†’        message: 'Gmail client is not authenticated. Please authenticate before fetching emails.',
    99в†’      });
   100в†’      return result;
   101в†’    }
   102в†’
   103в†’    // Step 2: Determine timestamp to fetch from
   104в†’    let fetchSince: Date | null = null;
   105в†’
   106в†’    if (sinceDate) {
   107в†’      // Use custom date if provided
   108в†’      fetchSince = sinceDate;
   109в†’      result.sinceTimestamp = sinceDate;
   110в†’    } else {
   111в†’      // Query last email timestamp from database
   112в†’      try {
   113в†’        fetchSince = await repository.getLastEmailTimestamp();
   114в†’        result.sinceTimestamp = fetchSince;
   115в†’      } catch (error) {
   116в†’        result.errors.push({
   117в†’          type: 'persistence',
   118в†’          message: `Failed to query last email timestamp: ${error instanceof Error ? error.message : String(error)}`,
   119в†’          originalError: error,
   120в†’        });
   121в†’        return result;
   122в†’      }
   123в†’    }
   124в†’
   125в†’    // Step 3: Fetch emails from Gmail API
   126в†’    let emails: EmailMessage[];
   127в†’    try {
   128в†’      if (fetchSince) {
   129в†’        // Fetch emails since timestamp
   130в†’        emails = await emailFetcher.fetchEmailsSince(fetchSince);
   131в†’      } else {
   132в†’        // No previous emails, fetch all (with default limit)
   133в†’        const fetchResult = await emailFetcher.fetchEmails({ maxResults: 100 });
   134в†’        emails = fetchResult.emails;
   135в†’      }
   136в†’
   137в†’      result.fetchedCount = emails.length;
   138в†’    } catch (error) {
   139в†’      result.errors.push({
   140в†’        type: 'fetch',
   141в†’        message: `Failed to fetch emails from Gmail API: ${error instanceof Error ? error.message : String(error)}`,
   142в†’        originalError: error,
   143в†’      });
   144в†’      return result;
   145в†’    }
   146в†’
   147в†’    // Step 4: Persist emails to database (if any were fetched)
   148в†’    if (emails.length > 0) {
   149в†’      try {
   150в†’        await repository.batchInsert(emails);
   151в†’        result.persistedCount = emails.length;
   152в†’        result.success = true;
   153в†’      } catch (error) {
   154в†’        result.errors.push({
   155в†’          type: 'persistence',
   156в†’          message: `Failed to persist emails to database: ${error instanceof Error ? error.message : String(error)}`,
   157в†’          originalError: error,
   158в†’        });
   159в†’        return result;
   160в†’      }
   161в†’    } else {
   162в†’      // No new emails, but operation was successful
   163в†’      result.success = true;
   164в†’    }
   165в†’
   166в†’    return result;
   167в†’  } finally {
   168в†’    // Update end time and duration
   169в†’    result.endTime = new Date();
   170в†’    result.durationMs = result.endTime.getTime() - result.startTime.getTime();
   171в†’  }
   172в†’}
   173в†’
   174в†’/**
   175в†’ * Parse command-line arguments
   176в†’ *
   177в†’ * Supports:
   178в†’ *   --since=YYYY-MM-DD   # Fetch emails since this date
   179в†’ *   --help               # Show usage information
   180в†’ */
   181в†’function parseArguments(): { sinceDate?: Date; showHelp: boolean } {
   182в†’  const args = process.argv.slice(2);
   183в†’  const result: { sinceDate?: Date; showHelp: boolean } = { showHelp: false };
   184в†’
   185в†’  for (const arg of args) {
   186в†’    if (arg === '--help' || arg === '-h') {
   187в†’      result.showHelp = true;
   188в†’      continue;
   189в†’    }
   190в†’
   191в†’    if (arg.startsWith('--since=')) {
   192в†’      const dateStr = arg.split('=')[1];
   193в†’      const parsedDate = new Date(dateStr);
   194в†’
   195в†’      if (isNaN(parsedDate.getTime())) {
   196в†’        throw new Error(`Invalid date format: ${dateStr}. Use YYYY-MM-DD format.`);
   197в†’      }
   198в†’
   199в†’      result.sinceDate = parsedDate;
   200в†’    }
   201в†’  }
   202в†’
   203в†’  return result;
   204в†’}
   205в†’
   206в†’/**
   207в†’ * Display usage information
   208в†’ */
   209в†’function displayHelp(): void {
   210в†’  console.log('==============================================');
   211в†’  console.log('Gmail Email Fetcher CLI');
   212в†’  console.log('==============================================\n');
   213в†’  console.log('Fetch emails from Gmail API and persist to database.\n');
   214в†’  console.log('Usage:');
   215в†’  console.log('  npm run fetch:emails                        # Fetch since last DB timestamp');
   216в†’  console.log('  npm run fetch:emails -- --since=2024-01-01  # Fetch since custom date');
   217в†’  console.log('  npm run fetch:emails -- --help              # Show this help\n');
   218в†’  console.log('Requirements:');
   219в†’  console.log('  - Gmail OAuth2 credentials (run `npm run authorize:gmail` first)');
   220в†’  console.log('  - Valid gmail-tokens.json file in current directory');
   221в†’  console.log('  - Database connection configured (see ENVIRONMENT.md)\n');
   222в†’}
   223в†’
   224в†’/**
   225в†’ * Format duration in human-readable format
   226в†’ */
   227в†’function formatDuration(ms: number): string {
   228в†’  if (ms < 1000) return `${ms}ms`;
   229в†’  if (ms < 60000) return `${(ms / 1000).toFixed(2)}s`;
   230в†’  return `${(ms / 60000).toFixed(2)}m`;
   231в†’}
   232в†’
   233в†’/**
   234в†’ * Load Gmail tokens from file
   235в†’ */
   236в†’function loadTokens(tokensPath: string): OAuth2Tokens {
   237в†’  try {
   238в†’    const tokensJson = fs.readFileSync(tokensPath, 'utf-8');
   239в†’    return JSON.parse(tokensJson) as OAuth2Tokens;
   240в†’  } catch (error) {
   241в†’    throw new Error(
   242в†’      `Failed to load tokens from ${tokensPath}: ${error instanceof Error ? error.message : String(error)}\n` +
   243в†’        'Run `npm run authorize:gmail` to obtain tokens.'
   244в†’    );
   245в†’  }
   246в†’}
   247в†’
   248в†’/**
   249в†’ * CLI entry point for fetch-emails command
   250в†’ *
   251в†’ * Parses command-line arguments and executes fetchAndPersistEmails.
   252в†’ * Handles authentication, logging, and error reporting.
   253в†’ *
   254в†’ * @example
   255в†’ * ```bash
   256в†’ * npm run fetch:emails                        # Fetch since last DB timestamp
   257в†’ * npm run fetch:emails -- --since=2024-01-01  # Fetch since custom date
   258в†’ * ```
