   355в†’
   356в†’    // Step 6: Display results
   357в†’    console.log('Step 6: Results\n');
   358в†’    console.log('в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ');
   359в†’
   360в†’    if (result.success) {
   361в†’      console.log('вњ… Fetch operation completed successfully!\n');
   362в†’      console.log(`рџ“Љ Summary:`);
   363в†’      console.log(`   Emails fetched: ${result.fetchedCount}`);
