   346в†’
   347в†’    // Combine with any existing query
   348в†’    const query = options.query ? `${dateQuery} ${options.query}` : dateQuery;
   349в†’
   350в†’    // Fetch all emails matching the query
   351в†’    const result = await this.fetchEmails({
   352в†’      ...options,
   353в†’      query,
   354в†’      fetchAll: true, // Fetch all emails since date
   355в†’    });
   356в†’
   357в†’    return result.emails;
   358в†’  }
   359в†’
   360в†’  /**
   361в†’   * Fetch single email by ID
   362в†’   *
   363в†’   * @param messageId - Gmail message ID
   364в†’   * @param format - Message format
   365в†’   * @returns Email message
   366в†’   */
   367в†’  async fetchEmailById(
   368в†’    messageId: string,
   369в†’    format: 'full' | 'minimal' | 'metadata' | 'raw' = 'full'
   370в†’  ): Promise<EmailMessage> {
   371в†’    const message = await this.gmailClient.getMessage(messageId, format, {
   372в†’      retryOnRateLimit: true,
   373в†’      maxRetries: 3,
   374в†’    });
   375в†’
   376в†’    return this.parseGmailMessage(message);
   377в†’  }
   378в†’
   379в†’  /**
   380в†’   * Fetch message details in batches
   381в†’   *
   382в†’   * @param messages - Message references from list API
   383в†’   * @param format - Message format
   384в†’   * @param batchSize - Number of messages to fetch concurrently
   385в†’   * @param continueOnError - Whether to continue on individual errors
   386в†’   * @param errors - Array to collect errors
   387в†’   * @returns Fetched email messages
   388в†’   * @private
   389в†’   */
   390в†’  private async fetchMessageDetails(
   391в†’    messages: gmail_v1.Schema$Message[],
   392в†’    format: string,
   393в†’    batchSize: number,
   394в†’    continueOnError: boolean,
   395в†’    errors: FetchError[]
   396в†’  ): Promise<EmailMessage[]> {
   397в†’    const emails: EmailMessage[] = [];
   398в†’
   399в†’    // Process in batches to avoid overwhelming the API
   400в†’    for (let i = 0; i < messages.length; i += batchSize) {
   401в†’      const batch = messages.slice(i, i + batchSize);
   402в†’      const batchPromises = batch.map(async (msg) => {
   403в†’        // Validate message ID
   404в†’        if (!msg.id) {
   405в†’          console.error('Message missing ID:', msg);
   406в†’          errors.push({
   407в†’            messageId: 'unknown',
   408в†’            error: 'Message missing ID from Gmail API',
   409в†’            timestamp: new Date(),
   410в†’          });
   411в†’          return null;
   412в†’        }
   413в†’
   414в†’        try {
   415в†’          const message = await this.gmailClient.getMessage(msg.id, format as 'full' | 'minimal' | 'metadata' | 'raw', {
   416в†’            retryOnRateLimit: true,
   417в†’            maxRetries: 3,
   418в†’          });
   419в†’          return this.parseGmailMessage(message);
   420в†’        } catch (error) {
   421в†’          const err = error as Error & { code?: string | number };
   422в†’          const errorMessage = err.message || 'Unknown error';
   423в†’
   424в†’          errors.push({
   425в†’            messageId: msg.id,
   426в†’            error: errorMessage,
   427в†’            errorCode: err.code,
   428в†’            stackTrace: process.env.NODE_ENV === 'development' ? err.stack : undefined,
   429в†’            timestamp: new Date(),
   430в†’          });
   431в†’
   432в†’          console.error(`Failed to fetch message ${msg.id}:`, err);
   433в†’
   434в†’          if (!continueOnError) {
   435в†’            throw error;
   436в†’          }
   437в†’
   438в†’          return null;
   439в†’        }
   440в†’      });
   441в†’
   442в†’      const batchResults = await Promise.all(batchPromises);
   443в†’      const validEmails = batchResults.filter((email): email is EmailMessage => email !== null);
   444в†’      emails.push(...validEmails);
   445в†’    }
   446в†’
   447в†’    return emails;
   448в†’  }
   449в†’
   450в†’  /**
   451в†’   * Parse Gmail API message into EmailMessage format
   452в†’   *
   453в†’   * @param message - Gmail API message
   454в†’   * @returns Parsed email message
   455в†’   * @throws Error if message is missing required id or threadId
   456в†’   * @private
   457в†’   */
   458в†’  private parseGmailMessage(message: gmail_v1.Schema$Message): EmailMessage {
   459в†’    // Validate required fields
   460в†’    if (!message.id) {
   461в†’      throw new Error('Gmail message missing required id field');
   462в†’    }
   463в†’    if (!message.threadId) {
   464в†’      throw new Error('Gmail message missing required threadId field');
   465в†’    }
   466в†’    if (!message.payload) {
   467в†’      throw new Error('Gmail message missing payload field');
   468в†’    }
   469в†’
   470в†’    // Extract headers
   471в†’    const headers = message.payload.headers || [];
   472в†’    const subject = this.getHeader(headers, 'Subject') || '(No Subject)';
   473в†’    const from = this.parseEmailAddress(this.getHeader(headers, 'From'));
   474в†’    const to = this.parseEmailAddressList(this.getHeader(headers, 'To')) || [];
   475в†’
   476в†’    if (!from) {
   477в†’      throw new Error('Gmail message missing valid From header');
   478в†’    }
   479в†’
   480в†’    // Parse date
   481в†’    const dateHeader = this.getHeader(headers, 'Date');
   482в†’    let date = new Date();
   483в†’    if (dateHeader) {
   484в†’      try {
   485в†’        const parsedDate = new Date(dateHeader);
   486в†’        // Validate that the date is valid
   487в†’        if (!isNaN(parsedDate.getTime())) {
   488в†’          date = parsedDate;
   489в†’        } else {
   490в†’          console.warn(`Invalid date header: ${dateHeader}, using current date`);
   491в†’        }
   492в†’      } catch (error) {
   493в†’        console.error(`Date parsing error for: ${dateHeader}, using current date`, error);
   494в†’      }
   495в†’    }
   496в†’
   497в†’    // Transform Gmail API payload to classification-engine format
   498в†’    const payload = this.transformPayload(message.payload);
   499в†’
   500в†’    // Build EmailMessage
   501в†’    const email: EmailMessage = {
   502в†’      id: message.id,
   503в†’      threadId: message.threadId,
   504в†’      gmailLabels: message.labelIds || [],
   505в†’      payload,
   506в†’      subject,
   507в†’      from,
   508в†’      to,
   509в†’      cc: this.parseEmailAddressList(this.getHeader(headers, 'Cc')),
   510в†’      bcc: this.parseEmailAddressList(this.getHeader(headers, 'Bcc')),
   511в†’      date,
   512в†’      snippet: message.snippet || undefined,
   513в†’      historyId: message.historyId || undefined,
   514в†’      sizeEstimate: message.sizeEstimate || undefined,
   515в†’      isProcessed: false,
   516в†’      processingPriority: 1,
   517в†’    };
   518в†’
   519в†’    // Extract body content
   520в†’    this.extractBodyContent(message.payload, email);
   521в†’
   522в†’    return email;
   523в†’  }
   524в†’
   525в†’  /**
   526в†’   * Transform Gmail API payload to classification-engine format
   527в†’   *
   528в†’   * @param gmailPayload - Gmail API message part
   529в†’   * @returns Transformed payload
   530в†’   * @private
   531в†’   */
   532в†’  private transformPayload(gmailPayload: gmail_v1.Schema$MessagePart): {
   533в†’    partId?: string;
   534в†’    mimeType: string;
   535в†’    filename?: string;
   536в†’    headers: EmailHeader[];
   537в†’    body?: MessagePartBody;
   538в†’    parts?: MessagePart[];
   539в†’  } {
   540в†’    return {
   541в†’      partId: gmailPayload.partId || undefined,
   542в†’      mimeType: gmailPayload.mimeType || 'text/plain',
   543в†’      filename: gmailPayload.filename || undefined,
   544в†’      headers: (gmailPayload.headers || []).map((h) => ({
   545в†’        name: h.name || '',
   546в†’        value: h.value || '',
   547в†’      })),
   548в†’      body: gmailPayload.body
   549в†’        ? {
   550в†’            attachmentId: gmailPayload.body.attachmentId || undefined,
   551в†’            size: gmailPayload.body.size || undefined,
   552в†’            data: gmailPayload.body.data || undefined,
   553в†’          }
   554в†’        : undefined,
   555в†’      parts: gmailPayload.parts ? gmailPayload.parts.map((p) => this.transformPayloadPart(p)) : undefined,
   556в†’    };
   557в†’  }
   558в†’
   559в†’  /**
   560в†’   * Transform Gmail API message part to classification-engine format
   561в†’   *
   562в†’   * @param gmailPart - Gmail API message part
   563в†’   * @returns Transformed message part
   564в†’   * @private
   565в†’   */
   566в†’  private transformPayloadPart(gmailPart: gmail_v1.Schema$MessagePart): MessagePart {
   567в†’    return {
   568в†’      partId: gmailPart.partId || '',
   569в†’      mimeType: gmailPart.mimeType || 'text/plain',
   570в†’      filename: gmailPart.filename || undefined,
   571в†’      headers: (gmailPart.headers || []).map((h) => ({
   572в†’        name: h.name || '',
   573в†’        value: h.value || '',
   574в†’      })),
   575в†’      body: gmailPart.body
   576в†’        ? {
   577в†’            attachmentId: gmailPart.body.attachmentId || undefined,
   578в†’            size: gmailPart.body.size || undefined,
   579в†’            data: gmailPart.body.data || undefined,
   580в†’          }
   581в†’        : undefined,
   582в†’      parts: gmailPart.parts ? gmailPart.parts.map((p) => this.transformPayloadPart(p)) : undefined,
   583в†’    };
   584в†’  }
   585в†’
   586в†’  /**
   587в†’   * Get header value by name
   588в†’   *
   589в†’   * @param headers - Email headers
   590в†’   * @param name - Header name
   591в†’   * @returns Header value or undefined
   592в†’   * @private
   593в†’   */
   594в†’  private getHeader(headers: gmail_v1.Schema$MessagePartHeader[], name: string): string | undefined {
   595в†’    const header = headers.find((h) => h.name?.toLowerCase() === name.toLowerCase());
   596в†’    return header?.value || undefined;
   597в†’  }
   598в†’
   599в†’  /**
   600в†’   * Parse email address from header value using RFC-compliant parser
   601в†’   *
   602в†’   * @param headerValue - Header value
   603в†’   * @returns Parsed email address or undefined
   604в†’   * @private
   605в†’   */
   606в†’  private parseEmailAddress(headerValue?: string): EmailAddress | undefined {
   607в†’    if (!headerValue) {
   608в†’      return undefined;
   609в†’    }
   610в†’
   611в†’    try {
   612в†’      const parsed = parseOneAddress(headerValue);
   613в†’      if (!parsed || parsed.type !== 'mailbox') {
   614в†’        console.warn(`Invalid email address format: ${headerValue}`);
   615в†’        return undefined;
   616в†’      }
   617в†’
   618в†’      return {
   619в†’        email: parsed.address,
   620в†’        name: parsed.name || undefined,
   621в†’        raw: headerValue,
   622в†’      };
   623в†’    } catch (error) {
   624в†’      console.error(`Email parsing failed for: ${headerValue}`, error);
   625в†’      return undefined;
   626в†’    }
   627в†’  }
   628в†’
   629в†’  /**
   630в†’   * Parse comma-separated email address list using RFC-compliant parser
   631в†’   *
   632в†’   * @param headerValue - Header value with comma-separated addresses
   633в†’   * @returns Array of parsed email addresses
   634в†’   * @private
   635в†’   */
   636в†’  private parseEmailAddressList(headerValue?: string): EmailAddress[] | undefined {
   637в†’    if (!headerValue) {
   638в†’      return undefined;
   639в†’    }
   640в†’
   641в†’    try {
   642в†’      const parsed = parseAddressList(headerValue);
   643в†’      if (!parsed) {
   644в†’        console.warn(`Invalid email address list: ${headerValue}`);
   645в†’        return undefined;
   646в†’      }
   647в†’
   648в†’      const addresses = parsed
   649в†’        .filter((addr) => addr.type === 'mailbox')
   650в†’        .map((addr) => ({
   651в†’          email: addr.address,
   652в†’          name: addr.name || undefined,
   653в†’          raw: headerValue,
   654в†’        }));
   655в†’
   656в†’      return addresses.length > 0 ? addresses : undefined;
   657в†’    } catch (error) {
   658в†’      console.error(`Email list parsing failed for: ${headerValue}`, error);
   659в†’      return undefined;
   660в†’    }
   661в†’  }
   662в†’
   663в†’  /**
   664в†’   * Extract body content from message payload with error handling
   665в†’   *
   666в†’   * @param part - Message part
   667в†’   * @param email - Email message to populate
   668в†’   * @private
   669в†’   */
   670в†’  private extractBodyContent(part: gmail_v1.Schema$MessagePart, email: EmailMessage): void {
   671в†’    // Check if this part has body data
   672в†’    if (part.body?.data) {
   673в†’      try {
   674в†’        const decodedData = Buffer.from(part.body.data, 'base64').toString('utf-8');
   675в†’
   676в†’        if (part.mimeType === 'text/plain') {
   677в†’          email.bodyPlain = decodedData;
   678в†’        } else if (part.mimeType === 'text/html') {
   679в†’          email.bodyHtml = decodedData;
   680в†’        }
   681в†’      } catch (error) {
   682в†’        console.error(`Failed to decode body for mimeType ${part.mimeType}:`, error);
   683в†’        // Continue processing other parts
   684в†’      }
   685в†’    }
   686в†’
   687в†’    // Recursively process nested parts
   688в†’    if (part.parts) {
   689в†’      for (const subPart of part.parts) {
   690в†’        this.extractBodyContent(subPart, email);
   691в†’      }
   692в†’    }
   693в†’  }
   694в†’}
