#!/usr/bin/env node
/**
 * Thread Label Verification Test
 *
 * This test script verifies whether fetching individual email messages in a thread
 * shows all of the labels consistently, or if only the head message of a thread
 * shows all of the applied labels.
 *
 * Test case: Emails with subject "Potential October Visit"
 *
 * Usage:
 *   npm run test:thread-labels
 *   # or directly:
 *   npx tsx src/cli/test-thread-labels.ts
 */

import * as fs from 'fs';
import * as path from 'path';
import { GmailClient, OAuth2Tokens } from '../gmail/gmail-client';
import { EmailFetcher } from '../gmail/email-fetcher';
import { loadEnvironment } from '../config/env';

/**
 * Load Gmail tokens from file
 */
function loadTokens(tokensPath: string): OAuth2Tokens {
  try {
    const tokensJson = fs.readFileSync(tokensPath, 'utf-8');
    return JSON.parse(tokensJson) as OAuth2Tokens;
  } catch (error) {
    throw new Error(
      `Failed to load tokens from ${tokensPath}: ${error instanceof Error ? error.message : String(error)}\n` +
        'Run `npm run authorize:gmail` to obtain tokens.'
    );
  }
}

/**
 * Main test execution
 */
async function main(): Promise<void> {
  // Load environment variables
  loadEnvironment();

  console.log('==============================================');
  console.log('Thread Label Verification Test');
  console.log('==============================================\n');

  // Step 1: Environment check
  console.log('Step 1: Checking Environment\n');

  const clientId = process.env.GMAIL_CLIENT_ID;
  const clientSecret = process.env.GMAIL_CLIENT_SECRET;
  const redirectUri = process.env.GMAIL_REDIRECT_URI;

  if (!clientId || !clientSecret || !redirectUri) {
    console.error('вќЊ Error: Missing Gmail OAuth2 credentials\n');
    process.exit(1);
  }

  console.log('вњ… Environment configured\n');

  // Step 2: Load tokens
  console.log('Step 2: Loading Gmail Tokens\n');

  const tokensPath = path.join(process.cwd(), 'gmail-tokens.json');
  let tokens: OAuth2Tokens;

  try {
    tokens = loadTokens(tokensPath);
    console.log(`вњ… Tokens loaded from: ${tokensPath}\n`);
  } catch (error) {
    console.error(`вќЊ ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }

  // Step 3: Initialize Gmail client
  console.log('Step 3: Initializing Gmail Client\n');

  const gmailClient = new GmailClient({
    clientId,
    clientSecret,
    redirectUri,
  });

  await gmailClient.setTokens(tokens);

  const authStatus = await gmailClient.getAuthStatus();
  if (!authStatus.authenticated || !authStatus.tokenValid) {
    console.error('вќЊ Error: Gmail authentication failed\n');
    process.exit(1);
  }

  console.log('вњ… Gmail client authenticated\n');

  // Step 4: Initialize email fetcher
  console.log('Step 4: Initializing Email Fetcher\n');

  const emailFetcher = new EmailFetcher(gmailClient);

  console.log('вњ… Email fetcher initialized\n');

  // Step 5: Search for emails with subject "Potential October Visit"
  console.log('Step 5: Searching for emails with subject "Potential October Visit"\n');

  const searchQuery = 'subject:"Potential October Visit"';
  console.log(`Search query: ${searchQuery}\n`);

  const searchResult = await emailFetcher.fetchEmails({
    query: searchQuery,
    maxResults: 50, // Get up to 50 messages to ensure we get full thread
    fetchAll: false,
  });

  console.log(`Found ${searchResult.totalFetched} email(s)\n`);

  if (searchResult.totalFetched === 0) {
    console.log('вљ пёЏ  No emails found with that subject. Test cannot proceed.\n');
    process.exit(0);
  }

  // Step 6: Group emails by thread and analyze labels
  console.log('Step 6: Analyzing Labels by Thread\n');
  console.log('==============================================\n');

  // Group emails by threadId
  const threadMap = new Map<string, typeof searchResult.emails>();

  for (const email of searchResult.emails) {
    const threadId = email.threadId;
    if (!threadMap.has(threadId)) {
      threadMap.set(threadId, []);
    }
    threadMap.get(threadId)!.push(email);
  }

  console.log(`Total threads found: ${threadMap.size}\n`);

  // Analyze each thread
  for (const [threadId, emails] of threadMap.entries()) {
    console.log(`Thread ID: ${threadId}`);
    console.log(`Messages in thread: ${emails.length}`);
    console.log('в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ');

    // Sort by date (oldest first)
    const sortedEmails = [...emails].sort((a, b) => a.date.getTime() - b.date.getTime());

    // Display each message with its labels
    sortedEmails.forEach((email, index) => {
      const position = index === 0 ? '(FIRST/HEAD)' : index === emails.length - 1 ? '(LAST)' : `(#${index + 1})`;
      console.log(`\nMessage ${index + 1} ${position}:`);
      console.log(`  ID: ${email.id}`);
      console.log(`  Date: ${email.date.toISOString()}`);
      console.log(`  Subject: ${email.subject}`);
      console.log(`  From: ${email.from.name || email.from.email}`);
      console.log(`  Labels (${email.gmailLabels.length}):`);

      if (email.gmailLabels.length === 0) {
        console.log('    (no labels)');
      } else {
        email.gmailLabels.forEach((label) => {
          console.log(`    - ${label}`);
        });
      }
    });

    console.log('\nв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ');

    // Analyze label consistency
    console.log('\nрџ“Љ Label Analysis for this Thread:');

    // Get all unique labels across all messages
    const allLabels = new Set<string>();
    sortedEmails.forEach((email) => {
      email.gmailLabels.forEach((label) => allLabels.add(label));
    });

    console.log(`\nUnique labels across all messages: ${allLabels.size}`);

    if (allLabels.size > 0) {
      console.log('\nLabel distribution:');

      for (const label of Array.from(allLabels).sort()) {
        const messagesWithLabel = sortedEmails.filter((email) => email.gmailLabels.includes(label));
        const percentage = ((messagesWithLabel.length / sortedEmails.length) * 100).toFixed(0);

        console.log(`  ${label}:`);
        console.log(`    Present in: ${messagesWithLabel.length}/${sortedEmails.length} messages (${percentage}%)`);

        if (messagesWithLabel.length !== sortedEmails.length) {
          console.log(`    вљ пёЏ  INCONSISTENT - Not all messages have this label!`);

          // Show which messages have it
          const positions = messagesWithLabel.map((msg) => {
            const idx = sortedEmails.indexOf(msg);
            return idx === 0 ? 'HEAD' : idx === sortedEmails.length - 1 ? 'LAST' : `#${idx + 1}`;
          });
          console.log(`    Present in positions: ${positions.join(', ')}`);
        } else {
          console.log(`    вњ… CONSISTENT - All messages have this label`);
        }
      }
    }

    console.log('\n==============================================\n');
  }

  // Step 7: Summary and conclusion
  console.log('Step 7: Summary\n');
  console.log('==============================================');
  console.log('Test Analysis Complete!\n');

  let hasInconsistentLabels = false;

  for (const [threadId, emails] of threadMap.entries()) {
    const allLabels = new Set<string>();
    emails.forEach((email) => {
      email.gmailLabels.forEach((label) => allLabels.add(label));
    });

    for (const label of allLabels) {
      const messagesWithLabel = emails.filter((email) => email.gmailLabels.includes(label));
      if (messagesWithLabel.length !== emails.length) {
        hasInconsistentLabels = true;
        break;
      }
    }

    if (hasInconsistentLabels) break;
  }

  if (hasInconsistentLabels) {
    console.log('вљ пёЏ  FINDING: Labels are NOT consistent across all messages in threads');
    console.log('\nThis means:');
    console.log('  - Some labels appear on only certain messages within a thread');
    console.log('  - We need to be careful when using labels for classification');
    console.log('  - We may need to fetch all messages in a thread to get complete label data');
  } else {
    console.log('вњ… FINDING: Labels are consistent across all messages in threads');
    console.log('\nThis means:');
    console.log('  - All messages in a thread have the same labels');
    console.log('  - We can rely on fetching just one message per thread for label data');
  }

  console.log('\n==============================================');
  console.log('Test Complete! рџЋ‰');
  console.log('==============================================\n');
}

// Run test if executed directly
if (require.main === module) {
  main()
    .then(() => process.exit(0))
    .catch((error) => {
      console.error('\nвќЊ Fatal error during test:');
      console.error(error instanceof Error ? error.message : String(error));

      if (error instanceof Error && error.stack) {
        console.error('\nStack trace:');
        console.error(error.stack);
      }

      process.exit(1);
    });
}

