        console.log(`  ${label}:`);
        console.log(`    Present in: ${messagesWithLabel.length}/${sortedEmails.length} messages (${percentage}%)`);

        if (messagesWithLabel.length !== sortedEmails.length) {
          console.log(`    вљ пёЏ  INCONSISTENT - Not all messages have this label!`);

          // Show which messages have it
          const positions = messagesWithLabel.map((msg) => {
            const idx = sortedEmails.indexOf(msg);
            return idx === 0 ? 'HEAD' : idx === sortedEmails.length - 1 ? 'LAST' : `#${idx + 1}`;
          });
          console.log(`    Present in positions: ${positions.join(', ')}`);
        } else {
          console.log(`    вњ… CONSISTENT - All messages have this label`);
        }
      }
    }

    console.log('\n==============================================\n');
  }

  // Step 7: Summary and conclusion
  console.log('Step 7: Summary\n');
  console.log('==============================================');
  console.log('Test Analysis Complete!\n');

  let hasInconsistentLabels = false;

  for (const [_threadId, emails] of threadMap.entries()) {
    const allLabels = new Set<string>();
    emails.forEach((email) => {
      email.gmailLabels.forEach((label) => allLabels.add(label));
    });

    for (const label of allLabels) {
      const messagesWithLabel = emails.filter((email) => email.gmailLabels.includes(label));
      if (messagesWithLabel.length !== emails.length) {
        hasInconsistentLabels = true;
        break;
      }
    }

    if (hasInconsistentLabels) break;
  }

  if (hasInconsistentLabels) {
    console.log('вљ пёЏ  FINDING: Labels are NOT consistent across all messages in threads');
    console.log('\nThis means:');
    console.log('  - Some labels appear on only certain messages within a thread');
    console.log('  - We need to be careful when using labels for classification');
    console.log('  - We may need to fetch all messages in a thread to get complete label data');
  } else {
    console.log('вњ… FINDING: Labels are consistent across all messages in threads');
    console.log('\nThis means:');
    console.log('  - All messages in a thread have the same labels');
    console.log('  - We can rely on fetching just one message per thread for label data');
  }

  console.log('\n==============================================');
  console.log('Test Complete! рџЋ‰');
  console.log('==============================================\n');
}

// Run test if executed directly
if (require.main === module) {
  main()
    .then(() => process.exit(0))
