   */
  clientId: string;

  /**
   * OAuth2 client secret from Google Cloud Console
   */
  clientSecret: string;

  /**
   * OAuth2 redirect URI for authorization callback
   */
  redirectUri: string;
}

/**
 * OAuth2 token set returned from Google
 */
