    console.error(`вќЊ ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }

  // Step 3: Initialize Gmail client
  console.log('Step 3: Initializing Gmail Client\n');

  const gmailClient = new GmailClient({
    clientId,
    clientSecret,
    redirectUri,
  });

  await gmailClient.setTokens(tokens);

  // Check token status and handle automatic refresh
  let authStatus = await gmailClient.getAuthStatus();

  if (!authStatus.authenticated) {
    console.error('вќЊ Error: No tokens set. Run `npm run authorize:gmail` first.\n');
    process.exit(1);
  }

  if (!authStatus.tokenValid) {
    console.log('вљ пёЏ  Access token expired. Attempting automatic refresh...\n');

