      const credentials = oauth2Client.credentials;

      if (!credentials.refresh_token) {
        console.error('вќЊ Error: No refresh token available. Please re-authorize:\n');
        console.error('   npm run authorize:gmail\n');
        process.exit(1);
      }

      // Manually refresh tokens
      const refreshedTokens = await gmailClient.refreshTokens();

      // Save refreshed tokens back to file
      console.log('рџ’ѕ Saving refreshed tokens...\n');
      fs.writeFileSync(tokensPath, JSON.stringify(refreshedTokens, null, 2));

      console.log('вњ… Tokens refreshed successfully\n');

      // Re-check auth status
      authStatus = await gmailClient.getAuthStatus();
      if (!authStatus.tokenValid) {
