#!/usr/bin/env node
/**
 * Thread Label Verification Test
 *
 * This test script verifies whether fetching individual email messages in a thread
 * shows all of the labels consistently, or if only the head message of a thread
 * shows all of the applied labels.
 *
 * Test case: Emails with subject "Potential October Visit"
 *
 * Usage:
 *   npm run test:thread-labels
 *   # or directly:
 *   npx tsx src/cli/test-thread-labels.ts
