import * as fs from 'fs';
import * as path from 'path';
import { GmailClient, OAuth2Tokens } from '../gmail/gmail-client';
import { EmailFetcher } from '../gmail/email-fetcher';
import { loadEnvironment } from '../config/env';

/**
 * Load Gmail tokens from file
 */
function loadTokens(tokensPath: string): OAuth2Tokens {
  try {
    const tokensJson = fs.readFileSync(tokensPath, 'utf-8');
    return JSON.parse(tokensJson) as OAuth2Tokens;
  } catch (error) {
    throw new Error(
      `Failed to load tokens from ${tokensPath}: ${error instanceof Error ? error.message : String(error)}\n` +
        'Run `npm run authorize:gmail` to obtain tokens.'
    );
  }
}

/**
 * Main test execution
 */
async function main(): Promise<void> {
  // Load environment variables
  loadEnvironment();

  console.log('==============================================');
  console.log('Thread Label Verification Test');
  console.log('==============================================\n');

  // Step 1: Environment check
  console.log('Step 1: Checking Environment\n');

  const clientId = process.env.GMAIL_CLIENT_ID;
  const clientSecret = process.env.GMAIL_CLIENT_SECRET;
  const redirectUri = process.env.GMAIL_REDIRECT_URI;

  if (!clientId || !clientSecret || !redirectUri) {
    console.error('вќЊ Error: Missing Gmail OAuth2 credentials\n');
    process.exit(1);
  }

  console.log('вњ… Environment configured\n');

  // Step 2: Load tokens
  console.log('Step 2: Loading Gmail Tokens\n');

  const tokensPath = path.join(process.cwd(), 'gmail-tokens.json');
  let tokens: OAuth2Tokens;

  try {
    tokens = loadTokens(tokensPath);
    console.log(`вњ… Tokens loaded from: ${tokensPath}\n`);
  } catch (error) {
    console.error(`вќЊ ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }

  // Step 3: Initialize Gmail client
  console.log('Step 3: Initializing Gmail Client\n');

  const gmailClient = new GmailClient({
    clientId,
    clientSecret,
    redirectUri,
  });

  await gmailClient.setTokens(tokens);

  // Check token status and handle automatic refresh
  let authStatus = await gmailClient.getAuthStatus();

  if (!authStatus.authenticated) {
    console.error('вќЊ Error: No tokens set. Run `npm run authorize:gmail` first.\n');
    process.exit(1);
  }

  if (!authStatus.tokenValid) {
    console.log('вљ пёЏ  Access token expired. Attempting automatic refresh...\n');

    // The Google OAuth2Client automatically refreshes on the next API call
    // Let's trigger a refresh by making a test call
    try {
      // Get OAuth2 client and check for refresh token
      const oauth2Client = gmailClient.getOAuth2Client();
      const credentials = oauth2Client.credentials;

      if (!credentials.refresh_token) {
        console.error('вќЊ Error: No refresh token available. Please re-authorize:\n');
        console.error('   npm run authorize:gmail\n');
        process.exit(1);
      }

      // Manually refresh tokens
      const refreshedTokens = await gmailClient.refreshTokens();

      // Save refreshed tokens back to file
      console.log('рџ’ѕ Saving refreshed tokens...\n');
      fs.writeFileSync(tokensPath, JSON.stringify(refreshedTokens, null, 2));

      console.log('вњ… Tokens refreshed successfully\n');

      // Re-check auth status
      authStatus = await gmailClient.getAuthStatus();
      if (!authStatus.tokenValid) {
        console.error('вќЊ Error: Token refresh succeeded but token still invalid\n');
        process.exit(1);
      }
    } catch (error) {
      console.error('вќЊ Error: Failed to refresh tokens\n');
      console.error(`   ${error instanceof Error ? error.message : String(error)}\n`);
      console.error('Please re-authorize: npm run authorize:gmail\n');
      process.exit(1);
    }
  }

  console.log('вњ… Gmail client authenticated\n');

  // Step 4: Initialize email fetcher
  console.log('Step 4: Initializing Email Fetcher\n');

  const emailFetcher = new EmailFetcher(gmailClient);

  console.log('вњ… Email fetcher initialized\n');

