// Step 3: Fetch emails from Gmail API using efficient thread-based approach
let allThreadMessages: EmailMessage[];
let newMessageIds: Set<string>;

try {
  if (fetchSince) {
    // Step 3a: First, do lightweight list to get new message refs and their thread IDs
    const year = fetchSince.getFullYear();
    const month = String(fetchSince.getMonth() + 1).padStart(2, '0');
    const day = String(fetchSince.getDate()).padStart(2, '0');
    const dateQuery = `after:${year}/${month}/${day}`;

    console.log(`Fetching messages since ${fetchSince.toISOString()}`);
    console.log(`Gmail query: ${dateQuery}`);

    const lightweightResult = await emailFetcher.fetchEmails({
      query: dateQuery,
      fetchAll: true,
      format: 'minimal', // Just get IDs and thread IDs (very lightweight)
    });

    if (lightweightResult.emails.length === 0) {
      console.log('No new messages found');
      result.success = true;
      return result;
    }

    // Track which messages are NEW (vs updated old messages in same threads)
    newMessageIds = new Set(lightweightResult.emails.map((e) => e.id));
    result.fetchedCount = newMessageIds.size;

    // Step 3b: Extract unique thread IDs from new messages
    const uniqueThreadIds = [...new Set(lightweightResult.emails.map((e) => e.threadId))];
    result.threadsAffected = uniqueThreadIds.length;

    console.log(`Found ${newMessageIds.size} new messages in ${uniqueThreadIds.length} threads`);
    console.log(`Using thread-based fetching (${uniqueThreadIds.length} API calls instead of ${newMessageIds.size})`);

    // Step 3c: Fetch complete threads (gets ALL messages with current labels!)
    const threadResult = await emailFetcher.fetchEmailsByThreads(uniqueThreadIds, {
      format: 'full',
      continueOnError: true,
    });

    allThreadMessages = threadResult.emails;
    console.log(`Retrieved ${allThreadMessages.length} total messages (includes old messages in threads)`);
  } else {
    // First fetch - use traditional approach (no previous data to sync)
    console.log('First fetch - fetching initial batch');
    const fetchResult = await emailFetcher.fetchEmails({ maxResults: 100 });
    allThreadMessages = fetchResult.emails;
    newMessageIds = new Set(allThreadMessages.map((e) => e.id));
    result.fetchedCount = allThreadMessages.length;
    result.threadsAffected = new Set(allThreadMessages.map((e) => e.threadId)).size;
  }
} catch (error) {
  result.errors.push({
    type: 'fetch',
    message: `Failed to fetch emails from Gmail API: ${error instanceof Error ? error.message : String(error)}`,
    originalError: error,
  });
  return result;
}

// Step 4: Persist ALL messages from fetched threads to database
// This updates labels on old messages and adds new messages!
if (allThreadMessages.length > 0) {
  try {
    console.log(`Persisting ${allThreadMessages.length} messages to database...`);
    await repository.batchInsert(allThreadMessages);
    result.persistedCount = allThreadMessages.length;
    result.success = true;

    const updatedCount = allThreadMessages.length - result.fetchedCount;
    if (updatedCount > 0) {
      console.log(`  в†і ${result.fetchedCount} new messages, ${updatedCount} updated messages`);
    }
  } catch (error) {
    result.errors.push({
      type: 'persistence',
      message: `Failed to persist emails to database: ${error instanceof Error ? error.message : String(error)}`,
      originalError: error,
    });
    return result;
  }
} else {
  // No new emails, but operation was successful
  result.success = true;
}

