#!/usr/bin/env node
/**
 * Incremental Email Fetch CLI (T042a)
 *
 * Wires together Gmail API integration (T037), email fetching (T038b),
 * and Prisma persistence (T042) to fetch and persist new emails since
 * the last recorded timestamp in the database.
 *
 * Usage:
 *   npm run fetch:emails                    # Fetch since last DB timestamp
 *   npm run fetch:emails -- --since=2024-01-01  # Fetch since custom date
 */

import * as fs from 'fs';
import * as path from 'path';
import { GmailClient, OAuth2Tokens } from '../gmail/gmail-client';
import { EmailFetcher, EmailMessage } from '../gmail/email-fetcher';
import { EmailRepository } from '../persistence/email-repository';
import { loadEnvironment } from '../config/env';

/**
 * Options for fetchAndPersistEmails function
 */
export interface FetchAndPersistOptions {
  gmailClient: GmailClient;
  emailFetcher: EmailFetcher;
  repository: EmailRepository;
  sinceDate?: Date; // Optional: Override last DB timestamp
}

/**
 * Error details for fetch/persist operations
 */
export interface FetchError {
  type: 'authentication' | 'fetch' | 'persistence';
  message: string;
  originalError?: unknown;
}

/**
 * Result summary for fetch and persist operation
 */
export interface FetchAndPersistResult {
  success: boolean;
  fetchedCount: number; // New messages since timestamp
  persistedCount: number; // Total messages persisted (new + updated from threads)
  threadsAffected: number; // Number of unique threads processed
  sinceTimestamp: Date | null;
  errors: FetchError[];
  startTime: Date;
  endTime: Date;
  durationMs: number;
}

/**
 * Fetch and persist new emails since last database timestamp
 *
 * This function implements the core logic for incremental email fetching:
 * 1. Query last email timestamp from database (unless sinceDate provided)
 * 2. Fetch new emails from Gmail API since that timestamp
 * 3. Persist emails using Prisma batch upsert
 * 4. Return detailed result summary with error handling
 *
 * @param options - Configuration for Gmail client, fetcher, and repository
 * @returns Result summary with counts, timestamps, and any errors
 *
 * @example
 * ```typescript
 * const result = await fetchAndPersistEmails({
 *   gmailClient: new GmailClient(auth),
 *   emailFetcher: new EmailFetcher(gmailClient),
 *   repository: new EmailRepository(),
 * });
 *
 * console.log(`Fetched ${result.fetchedCount} emails, persisted ${result.persistedCount}`);
 * ```
 */
export async function fetchAndPersistEmails(options: FetchAndPersistOptions): Promise<FetchAndPersistResult> {
  const { gmailClient, emailFetcher, repository, sinceDate } = options;

  const startTime = new Date();
  const result: FetchAndPersistResult = {
    success: false,
    fetchedCount: 0,
    persistedCount: 0,
    threadsAffected: 0,
    sinceTimestamp: null,
    errors: [],
    startTime,
    endTime: startTime, // Will be updated at end
    durationMs: 0,
  };

  try {
    // Step 1: Check Gmail authentication
    const authStatus = await gmailClient.getAuthStatus();
    if (!authStatus.authenticated || !authStatus.tokenValid) {
      result.errors.push({
        type: 'authentication',
        message: 'Gmail client is not authenticated. Please authenticate before fetching emails.',
      });
      return result;
    }

    // Step 2: Determine timestamp to fetch from
    let fetchSince: Date | null = null;

    if (sinceDate) {
      // Use custom date if provided
      fetchSince = sinceDate;
      result.sinceTimestamp = sinceDate;
    } else {
      // Query last email timestamp from database
      try {
        fetchSince = await repository.getLastEmailTimestamp();
        result.sinceTimestamp = fetchSince;
      } catch (error) {
        result.errors.push({
          type: 'persistence',
          message: `Failed to query last email timestamp: ${error instanceof Error ? error.message : String(error)}`,
          originalError: error,
        });
        return result;
      }
    }

    // Step 3: Fetch emails from Gmail API
    let emails: EmailMessage[];
    try {
      if (fetchSince) {
        // Fetch emails since timestamp
        emails = await emailFetcher.fetchEmailsSince(fetchSince);
      } else {
        // No previous emails, fetch all (with default limit)
        const fetchResult = await emailFetcher.fetchEmails({ maxResults: 100 });
        emails = fetchResult.emails;
      }

      result.fetchedCount = emails.length;
    } catch (error) {
      result.errors.push({
        type: 'fetch',
        message: `Failed to fetch emails from Gmail API: ${error instanceof Error ? error.message : String(error)}`,
        originalError: error,
      });
      return result;
    }

    // Step 4: Persist emails to database (if any were fetched)
    if (emails.length > 0) {
      try {
        await repository.batchInsert(emails);
        result.persistedCount = emails.length;
        result.success = true;
      } catch (error) {
        result.errors.push({
          type: 'persistence',
          message: `Failed to persist emails to database: ${error instanceof Error ? error.message : String(error)}`,
          originalError: error,
        });
        return result;
      }
    } else {
      // No new emails, but operation was successful
      result.success = true;
    }

    return result;
  } finally {
    // Update end time and duration
    result.endTime = new Date();
    result.durationMs = result.endTime.getTime() - result.startTime.getTime();
  }
}

/**
 * Parse command-line arguments
 *
 * Supports:
 *   --since=YYYY-MM-DD   # Fetch emails since this date
 *   --help               # Show usage information
 */
function parseArguments(): { sinceDate?: Date; showHelp: boolean } {
  const args = process.argv.slice(2);
  const result: { sinceDate?: Date; showHelp: boolean } = { showHelp: false };

  for (const arg of args) {
    if (arg === '--help' || arg === '-h') {
      result.showHelp = true;
      continue;
    }

    if (arg.startsWith('--since=')) {
      const dateStr = arg.split('=')[1];
      const parsedDate = new Date(dateStr);

      if (isNaN(parsedDate.getTime())) {
        throw new Error(`Invalid date format: ${dateStr}. Use YYYY-MM-DD format.`);
      }

      result.sinceDate = parsedDate;
    }
  }

  return result;
}

/**
 * Display usage information
 */
function displayHelp(): void {
  console.log('==============================================');
  console.log('Gmail Email Fetcher CLI');
  console.log('==============================================\n');
  console.log('Fetch emails from Gmail API and persist to database.\n');
  console.log('Usage:');
  console.log('  npm run fetch:emails                        # Fetch since last DB timestamp');
  console.log('  npm run fetch:emails -- --since=2024-01-01  # Fetch since custom date');
  console.log('  npm run fetch:emails -- --help              # Show this help\n');
  console.log('Requirements:');
  console.log('  - Gmail OAuth2 credentials (run `npm run authorize:gmail` first)');
  console.log('  - Valid gmail-tokens.json file in current directory');
  console.log('  - Database connection configured (see ENVIRONMENT.md)\n');
}

/**
 * Format duration in human-readable format
 */
function formatDuration(ms: number): string {
  if (ms < 1000) return `${ms}ms`;
  if (ms < 60000) return `${(ms / 1000).toFixed(2)}s`;
  return `${(ms / 60000).toFixed(2)}m`;
}

/**
 * Load Gmail tokens from file
 */
function loadTokens(tokensPath: string): OAuth2Tokens {
  try {
    const tokensJson = fs.readFileSync(tokensPath, 'utf-8');
    return JSON.parse(tokensJson) as OAuth2Tokens;
  } catch (error) {
    throw new Error(
      `Failed to load tokens from ${tokensPath}: ${error instanceof Error ? error.message : String(error)}\n` +
        'Run `npm run authorize:gmail` to obtain tokens.'
    );
  }
}

/**
 * CLI entry point for fetch-emails command
 *
 * Parses command-line arguments and executes fetchAndPersistEmails.
 * Handles authentication, logging, and error reporting.
 *
 * @example
 * ```bash
 * npm run fetch:emails                        # Fetch since last DB timestamp
 * npm run fetch:emails -- --since=2024-01-01  # Fetch since custom date
 * ```
 */
export async function main(): Promise<void> {
  // Load environment variables
  loadEnvironment();

  try {
    // Parse command-line arguments
    const { sinceDate, showHelp } = parseArguments();

    if (showHelp) {
      displayHelp();
      return;
    }

    console.log('==============================================');
    console.log('Gmail Email Fetcher');
    console.log('==============================================\n');

    // Step 1: Check environment variables
    console.log('Step 1: Checking Environment Configuration\n');

    const clientId = process.env.GMAIL_CLIENT_ID;
    const clientSecret = process.env.GMAIL_CLIENT_SECRET;
    const redirectUri = process.env.GMAIL_REDIRECT_URI;

    if (!clientId || !clientSecret || !redirectUri) {
      console.error('вќЊ Error: Missing Gmail OAuth2 credentials in environment variables.\n');
      console.error('Please set the following in your .env file:');
      console.error('  - GMAIL_CLIENT_ID');
      console.error('  - GMAIL_CLIENT_SECRET');
      console.error('  - GMAIL_REDIRECT_URI\n');
      console.error('See ENVIRONMENT.md for setup instructions.');
      process.exit(1);
    }

    console.log('вњ… Environment configured\n');

    // Step 2: Load Gmail tokens
    console.log('Step 2: Loading Gmail Tokens\n');

    const tokensPath = path.join(process.cwd(), 'gmail-tokens.json');
    let tokens: OAuth2Tokens;

    try {
      tokens = loadTokens(tokensPath);
      console.log(`вњ… Tokens loaded from: ${tokensPath}\n`);
    } catch (error) {
      console.error(`вќЊ ${error instanceof Error ? error.message : String(error)}`);
      process.exit(1);
    }

    // Step 3: Initialize Gmail client and verify authentication
    console.log('Step 3: Initializing Gmail Client\n');

    const gmailClient = new GmailClient({
      clientId,
      clientSecret,
      redirectUri,
    });

    await gmailClient.setTokens(tokens);

    const authStatus = await gmailClient.getAuthStatus();
    if (!authStatus.authenticated || !authStatus.tokenValid) {
      console.error('вќЊ Error: Gmail authentication failed.\n');
      console.error('Tokens may be expired or invalid. Run `npm run authorize:gmail` to obtain new tokens.');
      process.exit(1);
    }

    console.log('вњ… Gmail client authenticated\n');

    // Step 4: Initialize email fetcher and repository
    console.log('Step 4: Initializing Services\n');

    const emailFetcher = new EmailFetcher(gmailClient);
    const repository = new EmailRepository();

    console.log('вњ… Services initialized\n');

    // Step 5: Fetch and persist emails
    console.log('Step 5: Fetching Emails\n');

    if (sinceDate) {
      console.log(`Fetching emails since: ${sinceDate.toISOString()}`);
    } else {
      console.log('Fetching emails since last database timestamp (incremental fetch)');
    }

    console.log('This may take a moment...\n');

    const result = await fetchAndPersistEmails({
      gmailClient,
      emailFetcher,
      repository,
      sinceDate,
    });

    // Step 6: Display results
    console.log('Step 6: Results\n');
    console.log('в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ');

    if (result.success) {
      console.log('вњ… Fetch operation completed successfully!\n');
      console.log(`рџ“Љ Summary:`);
      console.log(`   Emails fetched: ${result.fetchedCount}`);
      console.log(`   Emails persisted: ${result.persistedCount}`);
      console.log(
        `   Since timestamp: ${result.sinceTimestamp ? result.sinceTimestamp.toISOString() : 'N/A (first fetch)'}`
      );
      console.log(`   Duration: ${formatDuration(result.durationMs)}`);

      if (result.fetchedCount === 0) {
        console.log('\nрџ’Ў No new emails found since last fetch.');
      }
    } else {
      console.log('вљ пёЏ  Fetch operation completed with errors:\n');
      console.log(`рџ“Љ Summary:`);
      console.log(`   Emails fetched: ${result.fetchedCount}`);
      console.log(`   Emails persisted: ${result.persistedCount}`);
      console.log(`   Errors: ${result.errors.length}`);
      console.log(`   Duration: ${formatDuration(result.durationMs)}\n`);

      console.log('вќЊ Errors encountered:');
      result.errors.forEach((error, index) => {
        console.log(`   ${index + 1}. [${error.type}] ${error.message}`);
      });

      process.exit(1);
    }

    console.log('в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ\n');

    console.log('Next steps:');
    console.log('  - Process emails: npm run process:gmail');
    console.log('  - Generate digests: npm run generate:digests\n');

    // Cleanup
    await repository.close();

    console.log('==============================================');
    console.log('Fetch Complete! рџЋ‰');
    console.log('==============================================\n');
  } catch (error) {
    console.error('\nвќЊ Fatal error during email fetching:');
    console.error(error instanceof Error ? error.message : String(error));

    if (error instanceof Error && error.stack) {
      console.error('\nStack trace:');
      console.error(error.stack);
    }

    console.error('\nCommon issues:');
    console.error('  - Gmail tokens expired (run `npm run authorize:gmail`)');
    console.error('  - Database connection failed (check ENVIRONMENT.md)');
    console.error('  - Network connectivity issues');
    console.error('  - Invalid --since date format (use YYYY-MM-DD)\n');

    process.exit(1);
  }
}

// Run CLI if executed directly
if (require.main === module) {
  main()
    .then(() => process.exit(0))
    .catch((error) => {
      console.error('Fatal error:', error);
      process.exit(1);
    });
}

