        where,
        orderBy: { sentAt: 'desc' },
        take: limit,
      });

      return results.map(this.dbToEmail);
    } catch (error) {
      throw new Error(`Failed to find unprocessed emails: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

